#!/bin/bash
# Deploy v6: Real AI queries via Perplexity + condensed scrollable table + revenue buckets
set -e
cd ~/chaos_tester

echo "=== Deploy v6: Real AI Queries + Scrollable Table ==="
echo ""

# -- ai_visibility.py --
echo "Decoding modules/ai_visibility.py..." && echo "" | base64 -d > modules/ai_visibility.py
echo "Decoding app.py..." && echo "" | base64 -d > app.py
echo "Decoding config.py..." && echo "" | base64 -d > config.py
echo "Decoding templates/report.html..." && echo "" | base64 -d > templates/report.html
echo "Decoding templates/dashboard.html..." && echo "" | base64 -d > templates/dashboard.html

echo ""
echo "Validating Python syntax..."
python3 -c "
import ast
for f in ['modules/ai_visibility.py', 'app.py', 'config.py']:
    ast.parse(open(f).read())
    print(f'  {f}: OK')
"

echo ""
echo "Committing..."
git add -A
git commit -m "feat: real AI queries via Perplexity + condensed scrollable results + revenue buckets

- Wire _run_ai_query() into run() for real Perplexity sonar API calls
- Fall back to simulation when no API key is provided
- Add revenue bucket parsing from AI response text
- Condense AI results table: show first 5 rows, expandable/scrollable
- Add Perplexity API key field to dashboard
- Read API key from form submission or PERPLEXITY_API_KEY env var
- Show green dot indicator for real (non-simulated) results
- Display competitor revenue brackets in results table"

echo ""
echo "Deploying to Cloud Run..."
gcloud run deploy chaos-tester \
  --project chaos-tester \
  --source . \
  --region us-central1 \
  --allow-unauthenticated \
  --quiet

echo ""
echo "Pushing to GitHub..."
git push origin main

echo ""
echo "=== v6 Deploy Complete ==="
echo ""
echo "Changes:"
echo "  1. AI queries now use Perplexity sonar API when API key is provided"
echo "  2. Dashboard has new 'Perplexity API Key' field"
echo "  3. Results table shows first 5 rows with 'Show All' expand button"
echo "  4. Competitors show revenue bucket estimates when available"
echo "  5. Green dot indicator marks real (non-simulated) query results"
echo ""
echo "To set API key as env var on Cloud Run:"
echo "  gcloud run services update chaos-tester --region us-central1 --set-env-vars PERPLEXITY_API_KEY=pplx-your-key-here"
